          # Fail if count INCREASES (ratchet pattern)
          BASELINE=247  # current count
          if [ "$DEPRECATED_COUNT" -gt "$BASELINE" ]; then
            echo "ERROR: New deprecated usages added!"
            exit 1
          fi

          # Update baseline when count decreases
          echo "DEPRECATED_BASELINE=$DEPRECATED_COUNT" >> migration-state.txt

  type-check-all-packages:
    steps:
      - run: pnpm tsc --noEmit -p packages/tr
